import React, { useState } from 'react';

const App = () => {
  const [dateFilter, setDateFilter] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [authorFilter, setAuthorFilter] = useState('');
  const [articles, setArticles] = useState([
    { title: 'Article 1', date: '2022-01-01', category: 'Category 1', author: 'Author 1', views: 100, comments: 10, engagement: 0.5 }
  ]);

  const handleDateFilterChange = (event) => {
    setDateFilter(event.target.value);
  };

  const handleCategoryFilterChange = (event) => {
    setCategoryFilter(event.target.value);
  };

  const handleAuthorFilterChange = (event) => {
    setAuthorFilter(event.target.value);
  };

  const filteredArticles = articles.filter((article) => {
    return article.date.includes(dateFilter) && article.category.includes(categoryFilter) && article.author.includes(authorFilter);
  });

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-100">
        <div className="flex justify-between mb-4">
          <div className="flex items-center">
            <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">Filter by date</button>
            <input className="ml-2 bg-[#B7D7CD] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" type="date" value={dateFilter} onChange={handleDateFilterChange} />
          </div>
          <div className="flex items-center">
            <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">Filter by category</button>
            <input className="ml-2 bg-[#B7D7CD] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" type="text" value={categoryFilter} onChange={handleCategoryFilterChange} />
          </div>
          <div className="flex items-center">
            <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">Filter by author</button>
            <input className="ml-2 bg-[#B7D7CD] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" type="text" value={authorFilter} onChange={handleAuthorFilterChange} />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr>
                <th>View count</th>
                <th>Comment count</th>
                <th>Engagement rate</th>
              </tr>
            </thead>
            <tbody>
              {filteredArticles.map((article) => (
                <tr key={article.title}>
                  <td>{article.views}</td>
                  <td>{article.comments}</td>
                  <td>{article.engagement}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default App;
